// Reune todas las filas del query en un historial plano (orden cronologico ASC ya viene del SQL).
// Formato de salida:
//   usuario: ...
//   Agente: ...
const rows = $input.all();
const input = $('Execute Workflow Trigger').first().json;

function parseMsg(raw) {
  if (!raw) return null;
  let obj = raw;
  if (typeof raw === 'string') {
    try { obj = JSON.parse(raw); } catch { return null; }
  }
  const type = obj.type || obj.role;
  const content = (obj.data && obj.data.content) || obj.content || '';
  if (!type || !content) return null;
  const roleLabel = (type === 'human' || type === 'user') ? 'usuario' : 'Agente';
  return `${roleLabel}: ${String(content).replace(/\s+/g, ' ').slice(0, 500)}`;
}

const lines = rows
  .map(r => parseMsg(r.json.message))
  .filter(Boolean);

const history = lines.length > 0 ? lines.join('\n') : '(sin historial previo)';

return [{ json: {
  session_id: input.session_id,
  message: input.message,
  chat_history: history,
} }];

// Une chat_history (Format History) + estado actual del lead (Fetch Lead State)
// y arma un unico string listo para el user prompt del agente.
const format = $('Format History').first().json;
const current = $input.first().json;

// El GET devuelve un array con 0 o 1 fila.
const row = Array.isArray(current) ? (current[0] || {}) : (current || {});

function fmt(v) {
  if (v === null || v === undefined || v === '') return '(vacio)';
  return String(v);
}

const estado = [
  `- parcela_interes: ${fmt(row.parcela_interes)}`,
  `- forma_pago: ${fmt(row.forma_pago)}`,
  `- plazo: ${fmt(row.plazo)}`,
  `- pie_disponible: ${fmt(row.pie_disponible)}`,
].join('\n');

const prompt = `Datos ya guardados en la base para este lead (si un campo dice (vacio) significa que NO se ha guardado todavia):\n${estado}\n\nConversacion completa entre el usuario y el Agente principal (en orden cronologico, el ultimo turno del usuario es la linea mas reciente que empieza con "usuario:"):\n\n"""\n${format.chat_history}\n"""`;

return [{ json: {
  prompt,
} }];
